1	import {
2	  createSkillFromNaturalLanguage,
3	  filterSkills,
4	  getNextStatus,
5	  scanSkill,
6	  seedSkills,
7	  statusOrder,
8	  sources,
9	  validateSkillId,
10	  validatePublishReady,
11	  validateImportFile,
12	  bundleFileTemplate
13	} from "../src/skills.js";
14	
15	const storageKey = "br_skill_resource_library_v2";
16	
17	const state = {
18	  page: "library",
19	  primaryTab: "space",
20	  resourceTab: "skill",
21	  skillView: "grid",
22	  keyword: "",
23	  status: "全部",
24	  source: "全部",
25	  createMode: "",
26	  editingId: "",
27	  detailId: "",
28	  detailTab: "overview",
29	  modal: "",
30	  importedFileName: "",
31	  activeFile: "SKILL.md",
32	  skills: loadSkills()
33	};
34	
35	let keywordTimer = null;
36	
37	const resourceTabs = [
38	  { id: "knowledge", label: "知识库" },
39	  { id: "database", label: "数据库" },
40	  { id: "plugin", label: "插件库" },
41	  { id: "skill", label: "技能" }
42	];
43	
44	const createTypes = [
45	  {
46	    id: "在线编写",
47	    title: "在线编写",
48	    subtitle: "进入编辑器编写 SKILL.md，可随时使用自然语言生成或补全内容",
49	    description: "进入编辑器编写 SKILL.md，可随时用自然语言生成或补全内容。",
50	    assets: ["SKILL.md", "manifest.json", "schema"]
51	  },
52	  {
53	    id: "代码仓库拉取",
54	    title: "代码仓库拉取",
55	    subtitle: "从已接入代码仓库读取技能包，按 manifest.json、skill.yaml、SKILL.md 优先级识别入口",
56	    description: "选择已接入的代码仓库，按 manifest.json、skill.yaml、SKILL.md 自动识别入口。",
57	    assets: ["manifest.json", "skill.yaml", "SKILL.md"]
58	  },
59	  {
60	    id: "导入技能包",
61	    title: "导入技能包",
62	    subtitle: "迁移已有资产",
63	    description: "先唤起上传窗口读取 md、json、yaml、zip，再进入同一个技能编辑器确认和发布。",
64	    assets: [".md", ".json", ".yaml", ".zip"]
65	  }
66	];
67	
68	// sources now imported from skills.js
69	
70	function loadSkills() {
71	  const saved = localStorage.getItem(storageKey);
72	  const skills = saved ? JSON.parse(saved) : seedSkills;
73	  // Migrate legacy skills (without files) to the new files-based format
74	  skills.forEach(skill => {
75	    if (!skill.files) {
76	      skill.files = {};
77	      const assets = skill.assets || [];
78	      if (assets.length > 0) {
79	        for (const asset of assets) {
80	          skill.files[asset] = asset === "SKILL.md" ? (skill.content || "") : bundleFileTemplate(asset);
81	        }
82	      } else {
83	        skill.files["SKILL.md"] = skill.content || "";
84	      }
85	      if (!skill.files["SKILL.md"]) {
86	        skill.files["SKILL.md"] = skill.content || "";
87	      }
88	      skill.assets = Object.keys(skill.files);
89	    }
90	  });
91	  return skills;
92	}
93	
94	function saveSkills() {
95	  localStorage.setItem(storageKey, JSON.stringify(state.skills));
96	}
97	
98	function render() {
99	  document.querySelector("#app").innerHTML = `
100	    <div class="layout">
101	      ${sidebar()}
102	      <main class="workspace">
103	        ${pageContent()}
104	      </main>
105	    </div>
106	    ${state.modal ? createMethodModal() : ""}
107	  `;
108	  bind();
109	}
110	
111	function pageContent() {
112	  if (state.page === "editor") return editorPage();
113	  if (state.page === "detail") return detailPage();
114	  return `${topChrome()}${resourceNavigation()}${resourceBody()}`;
115	}
116	
117	function sidebar() {
118	  return `
119	    <aside class="sidebar">
120	      <div class="brand">
121	        <span class="brand-mark">B</span>
122	        <strong>百融百工</strong>
123	      </div>
124	      <button class="create-agent">+ 创建智能体</button>
125	      <nav class="side-section"><span>广场</span><button>探索广场</button></nav>
126	      <nav class="side-section"><span>应用</span><button>批量任务</button></nav>
127	      <div class="space-card"><span class="space-icon">J</span><strong>jingxiu.zhao</strong><small>所有者</small></div>
128	      <nav class="side-section">
129	        <span>创作中心</span>
130	        <button>工作台</button>
131	        <button class="active">资源库</button>
132	        <button>效果评测</button>
133	      </nav>
134	      <nav class="side-section">
135	        <span>运行中心</span>
136	        <button>发布管理</button>
137	        <button>线上观测</button>
138	        <button>自动优化</button>
139	      </nav>
140	      <nav class="side-section">
141	        <span>管理中心</span>
142	        <button>空间管理</button>
143	        <button>文档中心</button>
144	      </nav>
145	      <div class="profile"><span class="avatar"></span><strong>jingxiu.zhao</strong></div>
146	    </aside>
147	  `;
148	}
149	
150	function topChrome() {
151	  return `
152	    <header class="page-head">
153	      <div class="title-row">
154	        <h1>资源库</h1>
155	        <div class="segmented" role="tablist">
156	          <button class="${state.primaryTab === "space" ? "active" : ""}" data-primary="space">空间资源库</button>
157	          <button class="${state.primaryTab === "public" ? "active" : ""}" data-primary="public">公开资源库</button>
158	        </div>
159	      </div>
160	      <label class="search">
161	        <span></span>
162	        <input id="keyword" value="${escapeHtml(state.keyword)}" placeholder="请输入关键词搜索" />
163	      </label>
164	    </header>
165	  `;
166	}
167	
168	function resourceNavigation() {
169	  return `
170	    <div class="resource-tabs">
171	      ${resourceTabs.map(tab => `
172	        <button class="${state.resourceTab === tab.id ? "active" : ""}" data-resource="${tab.id}">
173	          ${tab.label}${tab.id === "skill" ? "<i>NEW</i>" : ""}
174	        </button>
175	      `).join("")}
176	    </div>
177	  `;
178	}
179	
180	function resourceBody() {
181	  if (state.resourceTab !== "skill") return placeholderResource();
182	  return skillResource();
183	}
184	
185	function placeholderResource() {
186	  const copy = {
187	    knowledge: ["知识库", "沉淀文档、FAQ 和业务知识，供 Agent 检索引用。"],
188	    database: ["数据库", "配置结构化数据源，支持查询和分析任务。"],
189	    plugin: ["插件库", "连接外部系统，执行查数、发通知、建工单等动作。"]
190	  }[state.resourceTab];
191	  return `
192	    <section class="empty-resource">
193	      <div>
194	        <span class="big-icon">${copy[0].slice(0, 1)}</span>
195	        <h2>${copy[0]}</h2>
196	        <p>${copy[1]}</p>
197	      </div>
198	    </section>
199	  `;
200	}
201	
202	function skillResource() {
203	  const library = state.primaryTab === "public" ? "official" : "space";
204	  const skills = filterSkills(state.skills, {
205	    library,
206	    keyword: state.keyword,
207	    status: state.status,
208	    source: state.source
209	  });
210	  return `
211	    <section class="skill-page">
212	      <div class="skill-toolbar">
213	        <div class="toolbar-left">
214	          <div class="metric-pill"><strong>${skills.length}</strong><span>${library === "official" ? "官方技能" : "空间技能"}</span></div>
215	          <select id="statusFilter">${["全部", ...statusOrder].map(item => `<option ${state.status === item ? "selected" : ""}>${item}</option>`).join("")}</select>
216	          <select id="sourceFilter">${sources.map(item => `<option ${state.source === item ? "selected" : ""}>${item}</option>`).join("")}</select>
217	        </div>
218	        <div class="toolbar-right">
219	          <button data-action="batch">批量操作</button>
220	          ${library === "space" ? `<button class="primary" data-open-create-modal>+ 创建技能</button>` : ""}
221	          <button class="icon-btn ${state.skillView === "list" ? "active" : ""}" data-view-mode="list" title="列表视图">≡</button>
222	          <button class="icon-btn ${state.skillView === "grid" ? "active" : ""}" data-view-mode="grid" title="卡片视图">□</button>
223	        </div>
224	      </div>
225	      ${library === "space" ? "" : officialBanner()}
226	      ${skills.length ? `
227	        <div class="${state.skillView === "grid" ? "skill-grid" : "skill-list"}">
228	          ${skills.map(skill => state.skillView === "grid" ? skillCard(skill) : skillRow(skill)).join("")}
229	        </div>
230	      ` : emptySkills(library)}
231	    </section>
232	  `;
233	}
234	
235	function officialBanner() {
236	  return `
237	    <section class="generator-strip official">
238	      <div>
239	        <strong>官方技能库</strong>
240	        <p>官方技能可直接引用，也可以复制到空间后进入完整编辑页定制。</p>
241	      </div>
242	      <button data-switch-space>查看空间技能</button>
243	    </section>
244	  `;
245	}
246	
247	function skillCard(skill) {
248	  return `
249	    <article class="skill-card">
250	      <button class="card-hit" data-detail="${skill.id}" aria-label="查看 ${skill.name} 详情"></button>
251	      <div class="card-head">
252	        <span class="skill-icon">${skill.owner === "official" ? "官" : "S"}</span>
253	        <div>
254	          <h3>${skill.name}</h3>
255	          <button class="copy-id" data-copy="${skill.skillId}">${skill.skillId}</button>
256	        </div>
257	        ${statusBadge(skill.status)}
258	      </div>
259	      <p class="description">${skill.description}</p>
260	      <div class="tag-row">
261	        <span>${skill.source}</span>
262	        <span>${skill.category}</span>
263	        <span>${skill.assets.length} 个资产</span>
264	      </div>
265	      <div class="card-meta">
266	        <span>${skill.creator}</span>
267	        <span>智能体：${skill.agents}</span>
268	        <span>${skill.version}</span>
269	      </div>
270	      <div class="card-actions">${skillActions(skill)}</div>
271	    </article>
272	  `;
273	}
274	
275	function skillRow(skill) {
276	  return `
277	    <article class="skill-row">
278	      <span class="skill-icon">${skill.owner === "official" ? "官" : "S"}</span>
279	      <div class="row-main">
280	        <h3>${skill.name} <button class="copy-id" data-copy="${skill.skillId}">${skill.skillId}</button></h3>
281	        <p>${skill.description}</p>
282	      </div>
283	      <div class="row-col">${skill.source}<br><small>${skill.category}</small></div>
284	      <div class="row-col">${statusBadge(skill.status)}<br><small>${skill.version}</small></div>
285	      <div class="row-actions">${skillActions(skill)}</div>
286	    </article>
287	  `;
288	}
289	
290	function skillActions(skill) {
291	  if (skill.owner === "official") {
292	    return `
293	      <button data-detail="${skill.id}">详情</button>
294	      <button class="primary" data-copy-official="${skill.id}">复制到空间</button>
295	      <button data-reference="${skill.id}">直接引用</button>
296	    `;
297	  }
298	  const editable = `<button data-edit="${skill.id}">编辑</button>`;
299	  const publish = ["草稿", "扫描失败", "已下架"].includes(skill.status) ? `<button class="primary" data-request-publish="${skill.id}">发布</button>` : "";
300	  const unpublish = skill.status === "已发布" ? `<button data-unpublish="${skill.id}">下架</button>` : "";
301	  return `
302	    <button data-detail="${skill.id}">详情</button>
303	    ${editable}
304	    ${publish}
305	    ${unpublish}
306	    <button data-remove="${skill.id}">删除</button>
307	  `;
308	}
309	
310	function statusLabel(status) {
311	  return status === "扫描中" ? "安全审核中" : status === "草稿变更" ? "草稿变更" : status;
312	}
313	
314	function statusBadge(status) {
315	  const label = statusLabel(status);
316	  const tone = {
317	    "草稿": "neutral",
318	    "草稿变更": "warning",
319	    "扫描中": "info",
320	    "扫描失败": "danger",
321	    "已发布": "success",
322	    "已下架": "neutral"
323	  }[status] || "neutral";
324	  return `<span class="status ${tone}">${label}</span>`;
325	}
326	
327	function emptySkills(library) {
328	  return `
329	    <section class="empty-state">
330	      <span class="big-icon">S</span>
331	      <h2>${library === "official" ? "暂无匹配的官方技能" : "还没有空间技能"}</h2>
332	      <p>${library === "official" ? "调整搜索或筛选条件，查看平台维护的标准能力。" : "点击创建，先在弹窗选择创建方式，再进入编辑页。"}</p>
333	      ${library === "space" ? `<button class="primary" data-open-create-modal>创建技能</button>` : ""}
334	    </section>
335	  `;
336	}
337	
338	function createMethodModal() {
339	  return `
340	    <div class="modal-backdrop">
341	      <section class="method-modal">
342	        ${state.modal === "import" ? uploadPanel() : `
343	          <header class="method-head">
344	            <h2>创建技能</h2>
345	            <p>创建方式只决定初始内容来源。自然语言生成属于在线编写编辑器能力，不单独作为创建方式。选择后都会进入技能编辑器，完成确认后再发布。</p>
346	          </header>
347	          <div class="method-list">
348	            ${createTypes.map(type => `
349	              <button class="method-option" data-start-create="${type.id}" aria-label="${type.title}">
350	                ${methodIcon(type.id)}
351	                <span class="method-copy">
352	                  <strong>${type.title}</strong>
353	                  <small>${createMethodSubtitle(type)}</small>
354	                </span>
355	                <span class="method-chevron" aria-hidden="true">›</span>
356	              </button>
357	            `).join("")}
358	          </div>
359	          <footer class="method-footer">
360	            <button data-close-modal>取消</button>
361	          </footer>
362	        `}
363	      </section>
364	    </div>
365	  `;
366	}
367	
368	function createMethodSubtitle(type) {
369	  const subtitles = {
370	    "在线编写": "进入编辑器编写 SKILL.md，可随时用自然语言生成或补全内容。",
371	    "代码仓库拉取": "从已接入代码仓库读取技能包，按 manifest.json、skill.yaml、SKILL.md 优先级识别入口。",
372	    "导入技能包": "上传本地技能包，解析 Markdown、JSON、YAML、ZIP 后进入编辑器。"
373	  };
374	  return subtitles[type.id] || type.description;
375	}
376	
377	function methodIcon(type) {
378	  const tone = {
379	    "在线编写": "primary",
380	    "代码仓库拉取": "orange",
381	    "导入技能包": "violet"
382	  }[type] || "primary";
383	  const icons = {
384	    "在线编写": `<path d="M15.5 5.5 18 8l-8.8 8.8-3.7 1.1 1.1-3.7 8.9-8.7Z"></path><path d="m13.7 7.3 3 3"></path><path d="M5 6.5 3.5 5 5 3.5"></path><path d="M8 3.5 9.5 5 8 6.5"></path>`,
385	    "代码仓库拉取": `<path d="m12 18 7-5-2.3-7.2-2.4 4.5H9.7L7.3 5.8 5 13l7 5Z"></path><path d="m9.7 10.3 2.3 7.2 2.3-7.2"></path>`,
386	    "导入技能包": `<path d="M12 16V5"></path><path d="m8 9 4-4 4 4"></path><path d="M5 15v3h14v-3"></path>`
387	  };
388	  return `
389	    <span class="method-icon ${tone}" aria-hidden="true">
390	      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round">${icons[type]}</svg>
391	    </span>
392	  `;
393	}
394	
395	function uploadPanel() {
396	  return `
397	    <form class="upload-panel" id="uploadForm">
398	      <header class="method-head upload-head">
399	        <h2>导入技能包</h2>
400	        <p>上传 Markdown、JSON、YAML 或 ZIP 技能文件包。系统读取入口文件后进入编辑器，你可以继续补全、校验和发布。</p>
401	      </header>
402	      <label class="upload-box">
403	        <input type="file" name="skillFile" accept=".md,.json,.yaml,.yml,.zip">
404	        <span>点击选择文件</span>
405	        <small>${state.importedFileName || "尚未选择文件"}</small>
406	      </label>
407	      <div class="upload-error" id="uploadError"></div>
408	      <footer class="method-footer">
409	        <button type="button" data-close-modal>取消</button>
410	        <button class="primary" id="importSubmitBtn">导入并编辑</button>
411	      </footer>
412	    </form>
413	  `;
414	}
415	
416	function editorPage() {
417	  const rawSkill = state.editingId ? state.skills.find(item => item.id === state.editingId) : draftForMode(state.createMode);
418	  const mode = state.createMode || rawSkill?.source || "在线编写";
419	  // Ensure files exist
420	  if (!rawSkill.files) {
421	    rawSkill.files = { "SKILL.md": rawSkill.content || "" };
422	    rawSkill.assets = Object.keys(rawSkill.files);
423	  }
424	  const fileNames = Object.keys(rawSkill.files);
425	  const activeFile = (state.activeFile && fileNames.includes(state.activeFile))
426	    ? state.activeFile
427	    : (fileNames.includes("SKILL.md") ? "SKILL.md" : fileNames[0] || "SKILL.md");
428	  const activeContent = rawSkill.files[activeFile] || "";
429	  return `
430	    <section class="skill-editor-page">
431	      <form id="editorForm" class="skill-editor-shell">
432	        <header class="editor-topbar">
433	          <div class="editor-title">
434	            <button type="button" class="back-icon" data-back-library aria-label="返回资源库">‹</button>
435	            <span class="topbar-divider"></span>
436	            <strong>编辑器：${escapeHtml(rawSkill.name || "未命名技能")}</strong>
437	            ${statusBadge(rawSkill.status || "草稿")}
438	          </div>
439	          <div class="editor-actions">
440	            <span class="publish-note">发布后自动安全审核</span>
441	            <button type="submit" data-save-draft>保存草稿</button>
442	            <button type="button" class="primary" data-save-publish>发布</button>
443	          </div>
444	        </header>
445	        <aside class="editor-meta-panel">
446	          <section>
447	            <h2>基础信息</h2>
448	            <label>技能名称<input name="name" value="${escapeAttr(rawSkill.name)}"></label>
449	            <label>Skill ID<input name="skillId" value="${escapeAttr(rawSkill.skillId)}" ${state.editingId ? "" : ""}><span class="skillid-error" id="skillIdError"></span></label>
450	            <label>描述<textarea name="description" placeholder="请输入技能描述...">${escapeHtml(rawSkill.description)}</textarea></label>
451	          </section>
452	          ${editorModePanel(mode, rawSkill)}
453	        </aside>
454	        <main class="editor-workbench">
455	          <nav class="file-tabs" aria-label="技能文件">
456	            ${fileNames.map(name => `
457	              <button type="button" class="${name === activeFile ? "active" : ""}" data-file-tab="${escapeAttr(name)}">${escapeHtml(name)}</button>
458	            `).join("")}
459	          </nav>
460	          <div class="editor-split-view">
461	            <section class="source-pane">
462	              <textarea class="code-editor" name="file-content" data-file-key="${activeFile}" aria-label="${activeFile} 内容">${escapeHtml(activeContent)}</textarea>
463	            </section>
464	            <aside class="render-pane">
465	              ${filePreview(rawSkill, activeFile)}
466	              ${bundleFileTree(rawSkill)}
467	            </aside>
468	          </div>
469	        </main>
470	      </form>
471	    </section>
472	  `;
473	}
474	
475	function editorModePanel(mode, skill) {
476	  if (mode === "在线编写" || mode === "官方复制") {
477	    return `
478	      <section class="ai-panel">
479	        <h2>自然语言生成</h2>
480	        <label>业务需求<textarea name="prompt" placeholder="描述任务目标、适用场景、输入输出、约束规则">${escapeHtml(skill.description)}</textarea></label>
481	        <button type="button" class="primary full" data-generate-skill>生成 / 更新 Skill 内容</button>
482	      </section>
483	    `;
484	  }
485	  if (mode === "代码仓库拉取") {
486	    return `
487	      <section class="ai-panel">
488	        <h2>仓库来源</h2>
489	        <label>GitLab 服务器<select><option>gitlab.cn.example.com</option></select></label>
490	        <label>仓库<select><option>brclaw/skills/policy-qa</option><option>ops/skills/customer-care</option></select></label>
491	      </section>
492	      <section class="ai-panel">
493	        <h2>入口识别优先级</h2>
494	        <div class="priority-list">
